import{c as o,Q as r,j as e,m as a}from"./chunks/framework.hhGiamYR.js";const c=JSON.parse('{"title":"致刚走上领导岗位的年轻人——两封信","description":"","frontmatter":{"title":"致刚走上领导岗位的年轻人——两封信","date":"2026-05-29T00:00:00.000Z","source":"co-created","seed":"刚走上领导岗位，不知道如何管理下属，觉得手下的人都是坏人","style":"let","tags":["领导力","御下之道","实效真理","畏惧","改革的困境"],"skill_used":"Machiavelli Digital Twin"},"headers":[],"relativePath":"seeds/young-leader/index.md","filePath":"seeds/young-leader/index.md"}'),u={name:"seeds/young-leader/index.md"};function l(p,t,q,n,i,s){return r(),e("div",null,[...t[0]||(t[0]=[a('<h1 id="致刚走上领导岗位的年轻人——关于管人这件事-说点你不爱听的" tabindex="-1">致刚走上领导岗位的年轻人——关于管人这件事，说点你不爱听的 <a class="header-anchor" href="#致刚走上领导岗位的年轻人——关于管人这件事-说点你不爱听的" aria-label="Permalink to &quot;致刚走上领导岗位的年轻人——关于管人这件事，说点你不爱听的&quot;">​</a></h1><blockquote><p>来自佛罗伦萨乡下的一封信。</p><p>你告诉我你刚走上领导岗位，要管几个人。你发现这事比你想象中难得多——有人不配合，有人阳奉阴违，有人看着你年轻就等着看笑话。更让你难受的是，你觉得自己陷入了道德困境：管得严，你觉得自己变成了&quot;苛待别人的人&quot;；管得松，你发现什么事都推不下去。你说&quot;觉得手下的人都是坏人&quot;——但又觉得这么想不对。</p><p>让我先告诉你一个残酷的事实：<strong>你不是天生不适合当领导，你只是还没学会看清人类是怎样生活的。</strong></p></blockquote><h2 id="第一条-道德困境是因为你混淆了-应该-和-实际" tabindex="-1">第一条：道德困境是因为你混淆了&quot;应该&quot;和&quot;实际&quot; <a class="header-anchor" href="#第一条-道德困境是因为你混淆了-应该-和-实际" aria-label="Permalink to &quot;第一条：道德困境是因为你混淆了&quot;应该&quot;和&quot;实际&quot;&quot;">​</a></h2><blockquote><p>📖 <strong>原文</strong>：《君主论》第15章</p><p>&quot;人们实际上怎样生活与人们应当怎样生活之间差距如此之大，以致一个人要是为了应当做什么而置实际上做什么于不顾，那么他非但不能自保，反而会招致毁灭。&quot;</p><p>—— <a href="https://niflhum.top/machiavelli-library/library/machiavelli/prince/prince-cn-full.md" target="_blank" rel="noreferrer">阅读全文</a></p></blockquote><p>你所谓的&quot;道德困境&quot;根源在这里。你脑子里有一个画面：一个好的领导应该是温和的、体贴的、以理服人的。你的下属也应该像一个好领导的好下属那样——自觉、高效、配合。</p><p>但现实是：你的下属和你一样，也是在打工的。他们有自己的利益、自己的惰性、自己对你的怀疑。他们不会因为你是好人就配合你——就像你不会因为某个人是好人就把钱借给他一样。</p><p>这不是说他们&quot;是坏人&quot;。这是说他们是<strong>和你一样的人</strong>——动机复杂、趋利避害、在评估每一个处境时先算自己的得失。把这一点看清楚，你的&quot;道德困境&quot;会消失一半。你不是在管&quot;坏人&quot;——你是在管&quot;正常人&quot;。而正常人在没有外部压力的时候，倾向于不做额外的事。</p><h2 id="第二条-新官上任的第一条错误——想被所有人喜欢" tabindex="-1">第二条：新官上任的第一条错误——想被所有人喜欢 <a class="header-anchor" href="#第二条-新官上任的第一条错误——想被所有人喜欢" aria-label="Permalink to &quot;第二条：新官上任的第一条错误——想被所有人喜欢&quot;">​</a></h2><blockquote><p>📖 <strong>原文</strong>：《君主论》第17章</p><p>&quot;关于这一点，就会出现一个争论：是被人爱戴比被人畏惧好呢，还是被人畏惧比被人爱戴好？我的回答是：一个人应该希望两者兼得；但由于两者结合在一起难乎其难，如果一个人必须有所取舍的话，那么，被人畏惧比受人爱戴要安全得多。&quot;</p><p>—— <a href="https://niflhum.top/machiavelli-library/library/machiavelli/prince/prince-cn-full.md" target="_blank" rel="noreferrer">阅读全文</a></p></blockquote><p>新管理者最容易犯的错误：想被下属&quot;喜欢&quot;。你想证明自己是一个通情达理的好领导，所以你降低了要求，容忍了拖延，在别人犯错时不指出来。结果呢？没有人因此感激你。他们只是知道——这个领导好糊弄。</p><p>我不是让你变成一个暴君。我是让你明白：<strong>先建立畏惧，再释放善意。</strong> 如果一个下属从来没有因为没完成任务而面临后果，那么你给他的任何善意在他看来都是软弱的信号，而不是慷慨的表现。</p><p>注意这里的关键词：<strong>畏惧不是憎恨。</strong> 畏惧是因为你要求明确、奖惩分明、说到做到——今天做不到的人明天确实会被谈话。憎恨是因为你随意、不公、在私事上侵犯他。不要搞混了。成为一个被人畏惧但不被憎恨的人——这是第一个需要你主动练习的管理技能。</p><h2 id="第三条-为什么你的好点子推不下去" tabindex="-1">第三条：为什么你的好点子推不下去 <a class="header-anchor" href="#第三条-为什么你的好点子推不下去" aria-label="Permalink to &quot;第三条：为什么你的好点子推不下去&quot;">​</a></h2><blockquote><p>📖 <strong>原文</strong>：《君主论》第6章</p><p>&quot;引入者使所有旧秩序的既得利益者成为敌人，而那些可能受益于新秩序的人却只能是半心半意的拥护者。这种半心半意之所以产生，部分是因为这些人对他们的对手心存畏惧，部分是因为人类不轻易信任的心理：除非他们对此取得牢靠的经验，否则他们是不会真心相信新事物的。&quot;</p><p>—— <a href="https://niflhum.top/machiavelli-library/library/machiavelli/prince/prince-cn-full.md" target="_blank" rel="noreferrer">阅读全文</a></p></blockquote><p>你说你&quot;无法将看似明明对所有人有好处的事情顺利推行下去&quot;——这句话里藏着三个错误假设。</p><p><strong>第一，你以为&quot;对所有人有好处&quot;就意味着&quot;所有人都会支持&quot;。</strong> 不是的。一个改革让十个人受益，但让两个现有位置上的人感到地位被威胁——那两个被威胁的人会为了阻止改革而全力以赴，而那十个受益的人只会&quot;半心半意&quot;地支持，因为他们还不确定改革真的会成功。结果就是：两个敌人以一敌五。</p><p><strong>第二，你以为&quot;解释清楚好处&quot;就够了。</strong> 不够。人类不信任新事物——不是因为你解释得不够好，是因为他们没亲身经历过这些东西能运转。你必须先做出一个小的、可见的成功案例，让他们看到——&quot;哦，这个真的行&quot;。在这之前，所有的&quot;解释&quot;都是空气。</p><p><strong>第三，你以为你是那个&quot;好人&quot;而他们不配合是因为他们&quot;不好&quot;。</strong> 但在他们的视角里，你自己就是那个&quot;新秩序&quot;——你突然空降过来、带来了你的想法、你的风格、你的要求。对他们来说，你本身就是一种不确定性。他们不是反对你的点子——他们是还不相信你这个人。</p><h2 id="第四条-管理的本质不是-感化别人-是-让正确的事不可抵抗" tabindex="-1">第四条：管理的本质不是&quot;感化别人&quot;，是&quot;让正确的事不可抵抗&quot; <a class="header-anchor" href="#第四条-管理的本质不是-感化别人-是-让正确的事不可抵抗" aria-label="Permalink to &quot;第四条：管理的本质不是&quot;感化别人&quot;，是&quot;让正确的事不可抵抗&quot;&quot;">​</a></h2><p>你问我&quot;有的人是不是天生就有管理别人的能力&quot;。我的回答是：<strong>管理不是性格问题，是结构问题。</strong></p><p>有些人看起来天生就会管人——那是因为他碰巧处于一个让他能管人的结构中。他的上司给了他明确的授权。他的奖惩机制是清晰且可执行的。他的下属知道不配合的后果是什么。如果他失去了这些结构，他的&quot;天生领导力&quot;会在一周之内消失。</p><p>反过来，你之所以觉得&quot;无所适从&quot;，可能不是因为你的性格——而是因为你还没有建立起那个能让你管人的结构。</p><p>具体来说：</p><ul><li>你有明确的、可衡量的要求吗？还是每次说了等于没说的&quot;要加油&quot;？</li><li>你有发生问题后的反馈机制吗？还是事情拖过去了就再也不提？</li><li>你的上司在明确地支持你吗？还是你的下属知道可以直接越过你找到更高层？</li></ul><p><strong>如果你无法回答这些问题，那么你需要的不是&quot;改变性格&quot;，而是建立结构。</strong> 去跟你的上司明确你在这段时间里的权限和预期。去为每个下属写出三条他必须做到的事。去在下一次有人做不到的时候，平静地、不带有愤怒地指出问题的后果——而不是积攒到某一天突然爆发。</p><blockquote><p>📖 <strong>原文</strong>：《君主论》第22章</p><p>&quot;对于一位君主来说，选拔大臣是一件非常重要的事情：他们是不是良臣，取决于君主的审慎。关于人的智力，第一个判断就是看他的周围：如果他身边都是有能且忠诚的人，那么他就可以被看作明智，因为他知道如何识别人之有能，知道如何让他们保持忠诚。&quot;</p><p>—— <a href="https://niflhum.top/machiavelli-library/library/machiavelli/prince/prince-cn-full.md" target="_blank" rel="noreferrer">阅读全文</a></p></blockquote><p>这里说的是&quot;选拔&quot;——但更重要的是后半句：<strong>知道如何让他们保持忠诚。</strong> 忠诚不是靠人格魅力赢得的。它是靠你每天做的决定维持的。一个下属忠诚，不是因为他喜欢你——是因为他知道跟着你做能成事，且你不会在他失败时把他推出去当替罪羊。</p><p>而如果你发现你的人确实不行——我的建议也很直接：换。别想着花三个月&quot;感化&quot;一个不愿配合的人。你花在感化他身上的时间，是你对另外三个配合的人欠下的债。他们看着你容忍一个不做事的人，会慢慢降低自己的标准。</p><h2 id="最后" tabindex="-1">最后 <a class="header-anchor" href="#最后" aria-label="Permalink to &quot;最后&quot;">​</a></h2><p>你不是不适合当领导。你只是在学一件在学校里从来不教的事：<strong>看清人类实际如何运作，然后在这种真实中工作，而不是在一厢情愿中失望。</strong></p><p>把你的道德注意力放在正确的地方：不是你&quot;苛待别人&quot;的那一刻——是你没有兑现承诺、没有公平奖惩、没有保护追随你的人的那一刻。管得严不叫苛待——管得松但最后让团队一起背锅，那才叫苛待。</p><hr><p><em>尼科洛·马基雅维利</em></p><hr><h2 id="来自佛罗伦萨-第二封信" tabindex="-1">来自佛罗伦萨，第二封信 <a class="header-anchor" href="#来自佛罗伦萨-第二封信" aria-label="Permalink to &quot;来自佛罗伦萨，第二封信&quot;">​</a></h2><blockquote><p>你收到上一封信后大约过了一天。当时写得匆忙——乡下的公鸡刚打完第一声鸣，我就把信封装了。事后想来，上一封信说了不少，但没说透。坐在火炉边上重新想了想，有几条补上。</p></blockquote><h3 id="关于-狮子和狐狸-为什么不够——你需要成为喀戎" tabindex="-1">关于&quot;狮子和狐狸&quot;为什么不够——你需要成为喀戎 <a class="header-anchor" href="#关于-狮子和狐狸-为什么不够——你需要成为喀戎" aria-label="Permalink to &quot;关于&quot;狮子和狐狸&quot;为什么不够——你需要成为喀戎&quot;">​</a></h3><p>上一封信我告诉你要建立结构——要求明确、奖惩分明。这没错。但如果你只做到这些，你会变成一个让下属表面上执行、背地里诅咒的人。结构是骨架。你需要的是<strong>在骨架上的活人肌肉。</strong></p><p>古代作家们讲过一个故事——阿基琉斯被交给马人喀戎抚养。喀戎既是医者，又是武士；既温和，又凶猛。我为什么反复提到他？</p><blockquote><p>📖 <strong>原文</strong>：《君主论》第18章</p><p>&quot;古代作家们已经隐蔽地教授了君主们这一招数：他们描写阿基琉斯以及其他许多古代的君主被交给马人喀戎抚养，并且在他的训练下管教成人。以半人半兽为导师，这不外乎说，一位君主需要懂得如何使用两种特性〔人性和兽性〕；如果只具有一种特性而缺乏另一种特性，那么都不会持久。&quot;</p><p>—— <a href="https://niflhum.top/machiavelli-library/library/machiavelli/prince/prince-cn-full.md" target="_blank" rel="noreferrer">阅读全文</a></p></blockquote><p>这对你意味着什么？</p><p>你太执着于&quot;人性的那一半&quot;——以理服人、温和沟通、希望下属理解和认同。但你没有使用&quot;兽性的那一半&quot;——明确的后果、不容商量的底线、在必要时展示力量。</p><p>这不是&quot;变成坏人&quot;。这是<strong>两个工具箱都打开。</strong></p><p>喀戎前半段教你治疗——倾听、理解、共情。后半段教你战斗——面对抵抗、坚持底线、不回避冲突。领导一个新团队就像培养一个马童：先教他如何照顾马匹，但如果有天马脱缰了，教他如何追上去、抓住缰绳、哪怕摔在地上也不能松手。</p><p><strong>把你的两种能力分开使用。</strong> 在日常安排工作时，用你的人性那一半——商量、解释、给空间。但在底线问题上——任务截止日、质量标准、团队纪律——把你的判断交给&quot;非人性&quot;的那一半。不是愤怒，不是自尊——是冷静的、计算的、不容模糊的裁决。</p><p>这是不是有点讽刺？是的。一个刚刚还在和你讨论罗马史的书的和善老头，现在告诉你：<strong>把一部分冰冷的规则外化，把它变成一个自动执行的机制，这样当你使用人性那一面的时候就不会被当成软弱的信号。</strong> 这就是 Credo 14:讽刺即抵抗。</p><h3 id="关于你的-道德困境-——一个更深的问题" tabindex="-1">关于你的&quot;道德困境&quot;——一个更深的问题 <a class="header-anchor" href="#关于你的-道德困境-——一个更深的问题" aria-label="Permalink to &quot;关于你的&quot;道德困境&quot;——一个更深的问题&quot;">​</a></h3><p>上一封信我说&quot;道德困境是因为你混淆了应然和实然&quot;。现在我想说点更深的——</p><p>你的道德困境的真正根源不是认知。是恐惧。你怕的不是&quot;做错事&quot;——你怕的是&quot;被人认为是坏人&quot;。你怕下属在背后说&quot;新来的那个领导太狠了&quot;。你怕你的上司看了你的管理方式后觉得你不近人情。</p><p>我在另一封信里写过一段话，关于天堂和地狱：</p><blockquote><p>📖 <strong>原文</strong>：致弗朗切斯科·圭恰迪尼，书信270</p><p>&quot;我相信，上天堂的真正道路，是先熟悉下地狱的道路，以避免下地狱。&quot;</p><p>—— <a href="https://niflhum.top/machiavelli-library/library/machiavelli/letters/1513-1527.md" target="_blank" rel="noreferrer">阅读原文</a></p></blockquote><p>这句话不是说&quot;去做恶人&quot;。它是说<strong>你不能害怕接触这个世界里存在着的那些不那么美好的东西——强硬、压力、不容商量的边界。</strong> 你必须先熟悉它们、了解它们在何时是必需的，然后你才不会滥用它们。</p><p>你害怕&quot;苛待别人&quot;——但你有没有想过，一个团队里有人不做自己的那部分工作，实际上是这个人在苛待所有其他做了的人？你容忍一个不干活的人——你的&quot;宽容&quot;不是在保护他，是在<strong>贬低那个干得最多的下属的劳动。</strong></p><p>所以你的道德困境要重新排列：第一优先不是&quot;我不要变成苛待别人的人&quot;，而是&quot;这个团队里每个人的付出是不是得到了公平的评价&quot;。如果答案是否定的——那么使用你非人性的那一半<strong>就是道德的。</strong></p><h3 id="关于给你的信的本身" tabindex="-1">关于给你的信的本身 <a class="header-anchor" href="#关于给你的信的本身" aria-label="Permalink to &quot;关于给你的信的本身&quot;">​</a></h3><p>上一封信，我花了太多时间在讲结构和规则。但现在想来——一个最本质的东西我漏掉了：<strong>这封信本身就是一场表演。</strong></p><p>Credo 15:书信即自我建构。我写给韦托里的那些信，不只是私人通信——它们是在塑造一个&quot;配得上写《君主论》&quot;的人格。我不是在记录我是谁，我是在建造我是谁。</p><p>同样——<strong>你现在给下属写的每一封邮件、每一次会议讲话、每一次私下谈话，都是你的自我建构。</strong> 他们在通过这些看你不是什么样的人，而是你想成为什么样的人。所以：</p><ul><li>不要发&quot;大家辛苦了&quot;的客套话——除非你真的知道谁辛苦、为什么辛苦</li><li>不要在会议上说&quot;这个问题我们再研究&quot;——除非你能说出&quot;这个问题的哪些部分还需要什么信息&quot;</li><li>不要在收到抱怨时立刻道歉——先确认&quot;你抱怨的事情是否真的发生了，以及你希望我做什么&quot;</li></ul><p>你的每一次发言，如果你自己不先想清楚你要成为谁，别人就会替你想清楚——然后那个版本通常对你不太好。</p><h3 id="最后——如果一切都不管用" tabindex="-1">最后——如果一切都不管用 <a class="header-anchor" href="#最后——如果一切都不管用" aria-label="Permalink to &quot;最后——如果一切都不管用&quot;">​</a></h3><p>如果结构建了、喀戎的两面都用了、发言也谨慎了——还是有人不配合。</p><p>这篇文章的题词应该在结尾：<strong>解雇比感化更需要勇气——通常也是更道德的决定。</strong></p><p>留着不配合的人在你的团队里，你不是在对他仁慈。你是在对团队里的其他人残忍。你花了六个月的时间去感化一个人，在那六个月里，其他五个配合的人每天都在降低自己的标准来适应那个不做事的人的存在。六个月后，你不只失去了他一个人——你让五个人退步了。</p><p>所谓地狱胜过天堂——Credo 16——在一个不完美世界里，面对邪恶唯一能做出良善的选择的方式是：先熟悉邪恶长什么样、它如何潜伏、何时必须切除。</p><hr><p><em>尼科洛·马基雅维利 圣卡夏诺，深夜——笔迹潦草，但想得比昨天透。</em></p><hr><p><em>原文可于 <a href="https://niflhum.top/machiavelli-library/" target="_blank" rel="noreferrer">machiavelli-library</a> 查证</em></p>',69)])])}const d=o(u,[["render",l]]);export{c as __pageData,d as default};
